window.__QUIZ_DATA__=[{"id":"objective>Chemistry>2012>1","subject":"Chemistry","year":"2012","type":"Objective","topic":"STRUCTURE OF THE ATOM : ORBITALS","question":"The number of orbitals in a p - sub level of an atom is","images":[],"options":{"A":"2","B":"3","C":"5","D":"6"},"answer":"B","explanation":"In atomic physics and quantum chemistry, the electron configuration is the distribution of electrons of an atom or molecule in atomic or molecular orbitals. For example, the electron configuration of the neon atom is 1s2 2s2 2p6. The p sublevel has 3 orbitals, each of which can hold 2 electrons, for a total of 6 electrons.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2012>2","subject":"Chemistry","year":"2012","type":"Objective","topic":"STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION","question":"Which of the following electron configuration represents that of an atom in its ground state?","images":[],"options":{"A":"1s22s22p63s13p1","B":"1s22s12p1","C":"1s22s12p3","D":"1s22s22p63s0"},"answer":"D","explanation":"Ground-state configuration means the electrons hasn't been excited.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>3","subject":"Chemistry","year":"2012","type":"Objective","topic":"STRUCTURE OF THE ATOM : CHARACTERISTICS AND NATURE OF MATTER.","question":"A beam of particles was passed between charged plates as illustrated in the diagram beside.    X, Y and Z are respectively.","images":["data:image/png;base64,"],"options":{"A":"electron, neutron and proton","B":"electron, proton and neutron","C":"proton, neutron and electron","D":"proton, electron and neutron"},"answer":"C","explanation":"Electron (-ve) attracted to +ve changed plate.  Proton (+ve) attracted to -ve charged plate  Neutron (no charge)","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2012>4","subject":"Chemistry","year":"2012","type":"Objective","topic":"STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION","question":"Which of the following ions has an electron configuration different from the others?","images":[],"options":{"A":"17Cl-","B":"8O2-","C":"12Mg2+","D":"13Al3+"},"answer":"A","explanation":"Cl-1 has 18 electrons which has an electron configuration different from the others","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>5","subject":"Chemistry","year":"2012","type":"Objective","topic":"PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS","question":"The atomic radii of metals are usually","images":[],"options":{"A":"greater than their ionic radii","B":"equal to their ionic radii","C":"less than their ionic radii","D":"less than those of non-metals in the same period"},"answer":"A","explanation":"Atomic radii are usually greater than ionic radii \u2192 For metals   Atomic radii are usually lesser than ionic radii \u2192 For non-metals","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2012>6","subject":"Chemistry","year":"2012","type":"Objective","topic":"PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE","question":"Two elements, X and Y are in the same group on the periodic table because they both have the same","images":[],"options":{"A":"number of electronic shells","B":"number of valence electrons","C":"atomic size","D":"atomic number"},"answer":"B","explanation":"Elements in the same group on the periodic table have the same number of valence electrons. Valence electrons are the electrons in the outermost shell of an atom and determine an atom's ability to form bonds with other atoms.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2012>7","subject":"Chemistry","year":"2012","type":"Objective","topic":"PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.","question":"The d-block elements are paramagnetic because they","images":[],"options":{"A":"contain paired electrons which are repelled by magnetic field","B":"contain unpaired electrons in the partially filled 3d-orbital","C":"form coloured complex ions that attract magnetic lines of force","D":"have delocalized valence electrons"},"answer":"B","explanation":"The d-block elements are paramagnetic because they contain unpaired electrons in the partially filled 3d-orbital. Paramagnetism refers to the magnetic state of an atom with one or more unpaired electrons. The unpaired electrons are attracted by a magnetic field due to the electron's magnetic dipole moment.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>8","subject":"Chemistry","year":"2012","type":"Objective","topic":"STRUCTURE OF THE ATOM : CHARACTERISTICS AND NATURE OF MATTER.","question":"Which of the following statements about a radioactive substance is/are correct?   I. It emits radiation continuously and spontaneously   II. The emitted radiations are affected by temperature and pressure   III The radiation can penetrate opaque matter.","images":["data:image/png;base64,"],"options":{"A":"II only","B":"I and II only","C":"I and III only","D":"II and III only"},"answer":"C","explanation":"A radioactive substance will emit radiations spontaneously    * The emission of radiations by a radioactive substance should not be affected by temperature    * Radiations have different penetrating powers and can pass through opaque materials.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2012>9","subject":"Chemistry","year":"2012","type":"Objective","topic":"PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE","question":"Which of the following elements is a metalloid?","images":[],"options":{"A":"Carbon","B":"Oxygen","C":"Silicon","D":"Sodium"},"answer":"C","explanation":"Silicon is a metalloid. Metalloids have properties of both metals and non-metals. Silicon, for example, has lustrous shine like a metal, is a good conductor of electricity like a metal, but is brittle and not malleable like a non-metal.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2012>10","subject":"Chemistry","year":"2012","type":"Objective","topic":"PERIODIC CHEMISTRY : PERIODIC GRADATION OF ELEMENTS IN GROUP SEVEN, THE HALOGENS: F, CL, BR AND I","question":"Which of the following halogens is liquid at room temperature?","images":[],"options":{"A":"Chlorine","B":"Fluorine","C":"Iodine","D":"Bromine"},"answer":"D","explanation":"Bromine is the only halogen that is liquid at room temperature. Halogens are the elements in Group 17 of the periodic table. They include fluorine, chlorine, bromine, iodine, and astatine. All halogens have 7 valence electrons.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2012>11","subject":"Chemistry","year":"2012","type":"Objective","topic":"STATES OF MATTER : DIAMOND AND GRAPHITE","question":"The shape of a graphite crystal is","images":[],"options":{"A":"tetrahedral","B":"pyramidal","C":"hexagonal","D":"octahedral"},"answer":"C","explanation":"The shape of a graphite crystal is hexagonal. Graphite is an allotrope of carbon where the carbon atoms are arranged in a hexagonal manner. This arrangement results in layers or sheets of carbon atoms.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>12","subject":"Chemistry","year":"2012","type":"Objective","topic":"CHEMICAL BONDS : IONIC COMPOUNDS","question":"The compound formed by the combination of two elements with a large electronegativity difference is likely to be","images":[],"options":{"A":"polar covalent","B":"giant molecular","C":"covalent","D":"ionic"},"answer":"D","explanation":"When two elements with a large electronegativity difference combine, they form an ionic compound. This is because the element with the higher electronegativity will attract the electrons from the other element, resulting in the formation of ions. These ions then attract each other to form an ionic compound.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>13","subject":"Chemistry","year":"2012","type":"Objective","topic":"ACIDS, BASES AND SALTS : BASES","question":"The complex compound formed when Aluminium dissolves in aqueous Sodium Hydroxide is","images":[],"options":{"A":"Na3Al(OH)4","B":"NaAl(OH)4","C":"NaAl(OH)3","D":"Na2Al(OH)3"},"answer":"B","explanation":"When aluminium dissolves in aqueous sodium hydroxide, the complex compound formed is NaAl(OH)4. This is because aluminium reacts with sodium hydroxide to form a complex ion, Al(OH)4-, which then combines with the sodium ions to form the compound.","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2012>14","subject":"Chemistry","year":"2012","type":"Objective","topic":"STATES OF MATTER : LIQUIDS","question":"The vapour pressure of a liquid depends on    I. temperature    II. rate of condensation    III. cohesive forces holding the particles together.","images":[],"options":{"A":"I only","B":"I and II only","C":"I and III only","D":"II and III only"},"answer":"C","explanation":"Vapour pressure depends on temperature and the intermolecular forces holding the individual atoms together","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>15","subject":"Chemistry","year":"2012","type":"Objective","topic":"SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES","question":"MgO does not readily dissolve in water because","images":[],"options":{"A":"of its high melting point","B":"it is a covalent compound","C":"it forms a hydroxide when dissolved in water","D":"its lattice energy is higher than its hydration energy"},"answer":"D","explanation":"MgO does not readily dissolve in water because its lattice energy is higher than its hydration energy. Lattice energy is the energy required to separate the ions in an ionic compound, while hydration energy is the energy released when the ions are surrounded by water molecules. If the lattice energy is higher than the hydration energy, the compound will not dissolve readily in water.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>16","subject":"Chemistry","year":"2012","type":"Objective","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"Consider the following reaction equation:   CaCO3(s) + 2HCl(aq) \u2192 CaCl2(aq) + H2O(l) + CO2(g)    What mass of CaCl2would be obtained when 25.0g of CaCO3(s)is reacted with excess HClaq? [CaCO3 = 100, CaCl2 = 111]","images":[],"options":{"A":"4.00g","B":"4.44g","C":"18.9g","D":"27.8g"},"answer":"D","explanation":"CaCO3(s) + 2HCl(aq) \u2192 CaCl2(aq) + H2O(l) + CO2(g)   1 mole of CaCO3 \u2261 1 mol of CaCl2  100g of CaCO3 \u2261 111g of CaCl2  25g of CaCO3 \u2261 xg of CaCl2  x=25\u00d7111100  x = 27.8g","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2012>17","subject":"Chemistry","year":"2012","type":"Objective","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"The number of sulphur atoms in 3.20g of SO2(g) is    [O = 16.0; S = 32.), Avogadro constant = 6.02 x 1023]","images":[],"options":{"A":"3.01 x 1022","B":"6.02 x 1022","C":"6.02 x 1023","D":"1.20 x 1024"},"answer":"A","explanation":"The molar mass of SO2 is 64g/mol (32g for S and 16g for each O). Therefore, 3.20g of SO2 is 0.05 moles (3.20g / 64g/mol). Since each molecule of SO2 contains one S atom, there are 0.05 moles of S atoms in 3.20g of SO2. Using Avogadro's number (6.02 x 10^23), we find that 0.05 moles of S atoms is 3.01 x 10^22 atoms (0.05 x 6.02 x 1023.","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2012>18","subject":"Chemistry","year":"2012","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS","question":"Consider the reaction represented by the following equation: xCH3OH + yO2 \u2192 2CO2 + zH2O.    The value of x, y and z respectively are","images":[],"options":{"A":"2, 3 and 4","B":"2, 4 and 3","C":"1, 2 and 3","D":"1, 3 and 5"},"answer":"A","explanation":"The balanced chemical equation for the reaction is 2CH3OH + 3O2 \u2192 2CO2 + 4H2O. Therefore, the values of x, y, and z are 2, 3, and 4 respectively.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>19","subject":"Chemistry","year":"2012","type":"Objective","topic":"CHEMICAL BONDS : IONIC COMPOUNDS","question":"The formular of mercury (1)dioxonitrate (III) is","images":[],"options":{"A":"HgNO3","B":"Hg2NO3","C":"Hg(NO2)2","D":"Hg2(NO3)2"},"answer":"C","explanation":"Hg2+ &nbsp &nbsp &nbsp &nbsp NO2-  +2 &nbsp &nbsp &nbsp &nbsp 1  Hg(NO2)2","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>20","subject":"Chemistry","year":"2012","type":"Objective","topic":"NON METALS AND THEIR COMPOUNDS : HALOGENS","question":"A sample of a gas may be identified as chlorine if it turns","images":[],"options":{"A":"damp blue litmus paper red","B":"lime water milky","C":"lead ethanoate  paper black","D":"starch iodine paper blue-black"},"answer":"D","explanation":"Oxidation ability of Cl2, chlorine turns moist starch-iodide paper blue because it laces iodine from the iodide, The iodine liberated hen turns he starch blue black. 2Klaq + Cl2g \u2192 2KCl2 + l2g","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>21","subject":"Chemistry","year":"2012","type":"Objective","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : LAWS OF CHEMICAL COMBINATION.","question":"A metal M forms two types of chlorine, MCl2 and MCl3 . Which of the following laws best explains the relationship between the chlorides? Law of","images":[],"options":{"A":"conservation of mass","B":"definite proportion","C":"multiple proportion","D":"reciprocal proportion"},"answer":"C","explanation":"The law of multiple proportions states that when one element combines with another to form more than one compound, the mass ratios of the elements in the compounds are simple whole numbers of each other. In this case, the metal M forms two compounds with chlorine, MCl2 and MCl3. The ratio of chlorine to M in the two compounds is 2:1 and 3:1, which are simple whole numbers of each other. Therefore, the law of multiple proportions best explains the relationship between the chlorides.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>22","subject":"Chemistry","year":"2012","type":"Objective","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Which of the following metals would readily displace hydrogen from steam?","images":[],"options":{"A":"Copper","B":"Lead","C":"Magnesium","D":"Silver"},"answer":"C","explanation":"Magnesium is a more reactive metal and can readily displace hydrogen from steam. This is based on the reactivity series of metals, where magnesium is higher than hydrogen, meaning it can displace hydrogen from its compounds.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2012>23","subject":"Chemistry","year":"2012","type":"Objective","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"The volume occupied by 0.4g of hydrogen gas at s.t.p is   [H = 1.00, Molar volume at s.t.p = 22.4dm3]","images":[],"options":{"A":"2.24dm3","B":"4.48dm3","C":"22.4dm3","D":"44.8dm3"},"answer":"B","explanation":"H2 \u2192 2g (1 mol)  2g = 22.4dm3  6.4g \u2261x  x=22.4\u00d70.42=4.48dm3","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>24","subject":"Chemistry","year":"2012","type":"Objective","topic":"STATES OF MATTER : CHANGES OF STATE OF MATTER.","question":"When a substance changes directly from the solid state to the gaseous state without forming a liquid, the substance is said to","images":[],"options":{"A":"condense","B":"evaporate","C":"sublime","D":"precipitate"},"answer":"C","explanation":"When a substance changes directly from the gaseous state to the solid state without forming a liquid, the substance is said to sublime. This is a type of phase transition called sublimation.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2012>25","subject":"Chemistry","year":"2012","type":"Objective","topic":"NON METALS AND THEIR COMPOUNDS : WATER AND SOLUTION","question":"At ordinary temperature H2O is a liquid while H2S is a gas. This is because H2O has","images":[],"options":{"A":"weak intermolecular forces holding its molecules together","B":"strong hydrogen bonds holding its molecules together","C":"induced dipole-induced dipole forces between its molecules","D":"ionic forces between its molecules"},"answer":"B","explanation":"H2O is a liquid at ordinary temperature because it has strong hydrogen bonds holding its molecules together. These bonds require a significant amount of energy to break, which is why water remains a liquid at higher temperatures compared to H2S, which only has weak Van der Waals forces.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>26","subject":"Chemistry","year":"2012","type":"Objective","topic":"STATES OF MATTER : LIQUIDS","question":"The postulate that molecules are in constant random mention best explains why liquids","images":[],"options":{"A":"can undergo solidification","B":"maintain their volumes","C":"are incompressible","D":"have no characteristic shape"},"answer":"B","explanation":"Liquids are able to maintain their volumes because the molecules are in constant random motion. This motion allows the molecules to move freely within the liquid while remaining in close proximity to each other. Unlike gases, where molecules move freely and independently, liquid molecules are still closely packed together but have enough kinetic energy to move past each other, allowing liquids to flow and take the shape of their container.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>27","subject":"Chemistry","year":"2012","type":"Objective","topic":"STATES OF MATTER : GASES","question":"Which of the following gases has the lowest rate of diffusion under the same condition?    [H = 1.00, He = 4.00, O = 16.0; Cl = 35.5]","images":[],"options":{"A":"Cl2","B":"H2","C":"He","D":"O2"},"answer":"A","explanation":"From Graham's law,  Rateofdiffusion\u03b11&radic;Molar mass&nbsp;  Cl2 will have the lowest rate.  Cl2=35.5x2=1;rate=1\u221a7=0.12  H2=1x2=2;rate=1\u221a2=0.7071  O2=16x2=32;rate=1\u221a32=0.18","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2012>28","subject":"Chemistry","year":"2012","type":"Objective","topic":"ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY","question":"The energy evolved when magnesium burns in air is in the form of","images":[],"options":{"A":"heat","B":"heat and sound","C":"light and heat","D":"sound"},"answer":"C","explanation":"When magnesium burns in air, it reacts with oxygen to form magnesium oxide. This reaction is exothermic, meaning it releases energy in the form of heat and light. Therefore, the energy evolved when magnesium burns in air is in the form of light and heat.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>29","subject":"Chemistry","year":"2012","type":"Objective","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"A substance L reacts with NH4NO3(aq) to generate ammonia gas L is likely to be","images":[],"options":{"A":"HCl","B":"NaOH","C":"CH3COOH","D":"CaSO4"},"answer":"B","explanation":"NaOH reacting with NH4NO3 (which is a salt of strong acid and weak base)  NH4NO3 + NaOH \u2192 NaNO3 + NH3 + H2O","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>30","subject":"Chemistry","year":"2012","type":"Objective","topic":"ACIDS, BASES AND SALTS : SALTS","question":"On heating, the following trioxocarbonate (IV) salts decompose to give solid residue except","images":[],"options":{"A":"ammonium trioxocarbonate (IV)","B":"calcium trioxocarbonate (IV)","C":"lead(II)trioxocarbonate(IV)","D":"zinc trioxocarbonate(IV)"},"answer":"A","explanation":"Ammonium trioxocarbonate (IV) decomposes to give nitrogen, water and carbon dioxide gases with no solid residue. The other trioxocarbonate (IV) salts decompose to give a solid residue (metal oxide) and carbon dioxide gas.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>31","subject":"Chemistry","year":"2012","type":"Objective","topic":"ACIDS, BASES AND SALTS : CONCEPT OF PH","question":"Which of the following pH values indicates that a solution is a strong base?","images":[],"options":{"A":"1","B":"5","C":"9","D":"13"},"answer":"D","explanation":"The pH scale ranges from 0 to 14. A pH value of 7 indicates a neutral solution. pH values less than 7 indicate acidic solutions, and pH values greater than 7 indicate basic or alkaline solutions. Therefore, a pH value of 13 indicates a strong base.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2012>32","subject":"Chemistry","year":"2012","type":"Objective","topic":"ACIDS, BASES AND SALTS : SALTS","question":"The hydrolysis of NH4Cl gives","images":[],"options":{"A":"an acidic solution","B":"an alkaline solution","C":"a buffer solution","D":"a neutral solution"},"answer":"A","explanation":"Hydrolysis of NH4Cl gives NH3 solution and HCl which is a solution of weak base and strong acid therefore gives an overall acidic solution.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>33","subject":"Chemistry","year":"2012","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : SEPARATION AND PURIFICATION OF ORGANIC COMPOUNDS","question":"A spot of oil paint on a shirt can best be removed using","images":[],"options":{"A":"brine","B":"detergent","C":"kerosene","D":"warm water"},"answer":"C","explanation":"Oil-based paints are best removed using kerosene. This is because oil and kerosene are both non-polar substances and according to the principle of 'like dissolves like', non-polar substances dissolve in non-polar solvents.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2012>34","subject":"Chemistry","year":"2012","type":"Objective","topic":"SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES","question":"Which of the following deductions could be correctly made from the graph?","images":["data:image/png;base64,"],"options":{"A":"The solubility of U is not affected by change in temperature","B":"The solubility of S decreases with increasing temperature","C":"T is most soluble among the salts","D":"S is least soluble among the salts"},"answer":"A","explanation":"The straight line result obtained for U indicates that its solubility is unaffected by temperature change.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>35","subject":"Chemistry","year":"2012","type":"Objective","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"Consider the reaction represented by the following equation:  CuOs + H2SO4(aq) \u2192 CuSO4(aq) + H2O(l)   Which of the following factors will not affect the rate of the reaction?","images":[],"options":{"A":"Particle size CuO(s)","B":"Concentration of H2SO4(aq)","C":"Temperature of the reacting mixture","D":"Pressure of reaction system"},"answer":"D","explanation":"The pressure of the reaction system will not affect the rate of the reaction. This is because the reaction does not involve any gases. The rate of a reaction involving gases can be affected by pressure, but in this case, all reactants and products are either solids, liquids, or aqueous solutions.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>36","subject":"Chemistry","year":"2012","type":"Objective","topic":"ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY","question":"Use the following graph to answer this question       The activation energy for the reaction is","images":["data:image/png;base64,"],"options":{"A":"40 kJ","B":"60 kJ","C":"80 kJ","D":"120 kJ"},"answer":"A","explanation":"Activation energy is ( Activated complex - Reactant Energy) = 120 - 80 = 40kJ","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>37","subject":"Chemistry","year":"2012","type":"Objective","topic":"ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY","question":"Use the following graph to answer this question     The type of reaction represented by the graph is","images":["data:image/png;base64,"],"options":{"A":"endothermic","B":"exothermic","C":"catalytic","D":"spontaneous"},"answer":"B","explanation":"It is exothermic because \u0394Hproduct reactant","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>38","subject":"Chemistry","year":"2012","type":"Objective","topic":"REDOX REACTIONS : ELECTROCHEMICAL CELLS","question":"Which of the following devices function on redox reaction?  I. Dry cell   II. Car battery    III. Electric generator","images":[],"options":{"A":"I and III only","B":"II and III only","C":"I and II only","D":"I, II and III"},"answer":"C","explanation":"Dry cell and car battery function on redox reactions. A redox reaction is a type of chemical reaction that involves a transfer of electrons between two species. In both a dry cell and a car battery, there is a transfer of electrons from one species to another, which generates an electric current. An electric generator, on the other hand, operates on the principle of electromagnetic induction, not redox reactions.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2012>39","subject":"Chemistry","year":"2012","type":"Objective","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"The oxidation number of Fe in [Fe(CN60]3- is","images":[],"options":{"A":"+3","B":"+2","C":"-2","D":"-3"},"answer":"A","explanation":"The oxidation number of Fe in [Fe(CN6)]3- is +3. The oxidation number is a concept in chemistry that helps in balancing redox reactions. It represents the number of electrons that an atom can gain, lose, or share when chemically bonded with another atom. In this case, the overall charge of the complex ion is -3, and since each CN- ion has a charge of -1, the oxidation number of Fe must be +3 to balance the charge.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>40","subject":"Chemistry","year":"2012","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"Consider the following reaction equation:   C16H34 \u2192 C5H12 + C11H22    The process represented by the equation is","images":[],"options":{"A":"cracking","B":"fermentation","C":"polymerization","D":"reforming"},"answer":"A","explanation":"The process is cracking which involves the breakdown on higher hydrocarbon into smaller hydrocarbon fragment.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>41","subject":"Chemistry","year":"2012","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION","question":"Consider the following structures of organic compounds:      Which of the following statements about the structure is not correct?","images":["data:image/png;base64,"],"options":{"A":"are geometric isomers","B":"are saturated hydrocarbons","C":"have similar physical properties","D":"are members of the same homologous series"},"answer":"B","explanation":"It is unsaturated due to the presence of multiple bond.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>42","subject":"Chemistry","year":"2012","type":"Objective","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : ALCOHOLS","question":"Which of the following substances would not produce ethanol when fermented?","images":[],"options":{"A":"Cane sugar","B":"Glucose","C":"Starch","D":"Vinegar"},"answer":"D","explanation":"Vinegar would not produce ethanol when fermented. Fermentation is a process where sugars are converted into alcohol and carbon dioxide by the action of yeast or bacteria. Cane sugar, glucose, and starch are all sources of sugar that can be fermented to produce ethanol. Vinegar, on the other hand, is a product of fermentation (it's essentially fermented ethanol) and cannot be further fermented to produce ethanol.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>43","subject":"Chemistry","year":"2012","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS","question":"An alkanol can be prepared by the reaction of an alkene with","images":[],"options":{"A":"concentrated tetraoxosulphate (VI) acid","B":"bromine in tetrachloroethene","C":"aqueous potassium tetraoxomanganate(VII)","D":"sodium hydroxide solution"},"answer":"A","explanation":"Alkene + Concentrated H2SO4 at 180\u00b0C \u2192 Alkanol  N:B: If the reaction takes place at 140\u00b0C, it will produce an ether.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>44","subject":"Chemistry","year":"2012","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS","question":"A compound contains 7.75% Hydrogen, 37.21% Carbon and 55.04% Chlorine. Determine the empirical formular of the compound. [H = 1.00; C = 12.0, Cl = 35.5]","images":[],"options":{"A":"C3H3Cl","B":"C2H5Cl","C":"C3H8Cl","D":"C5H2I"},"answer":"B","explanation":"H  C  Cl  7.751:37.2112:55.04335.5  7.75: 3.10: 1.55; divide by the smallest ratio    7.751.55:3.101.55:1.551.55   5:2:1   empirical formula is C2H5Cl","marks":"1","difficulty":"3"},{"id":"objective>Chemistry>2012>45","subject":"Chemistry","year":"2012","type":"Objective","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS","question":"A tertiary alkanol has a molecular formular C4H10O. What is the structural formula of the compound?","images":[],"options":{"A":"(CH3)2CHCH2OH","B":"CH3CH2CH(OH)CH3","C":"(CH3)3COH","D":"CH3CH2CH2CH2OH"},"answer":"C","explanation":"Tertiary alkanol has 3 alkyl group attached to the carbon that is containing OH - functional group","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>46","subject":"Chemistry","year":"2012","type":"Objective","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : BIOTECHNOLOGY","question":"Which of the following industrial processes depends on the action of enzymes?","images":[],"options":{"A":"Liquefaction of air","B":"Manufacture of soap","C":"Brewing of beer","D":"Catalytic cracking"},"answer":"C","explanation":"The brewing of beer depends on the action of enzymes. Enzymes are biological catalysts that speed up chemical reactions. In the brewing process, enzymes in yeast convert the sugars in the grain into alcohol and carbon dioxide. The other options do not involve the use of enzymes.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2012>47","subject":"Chemistry","year":"2012","type":"Objective","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"Which of the following pollutants is not usually recycled?","images":[],"options":{"A":"Aluminium cans","B":"Glass bottles","C":"Nuclear wastes","D":"Paper wastes"},"answer":"C","explanation":"Nuclear wastes are not usually recycled due to the high level of radioactivity and the potential danger they pose. The process of recycling nuclear waste is complex, expensive, and poses significant health and environmental risks. Therefore, nuclear wastes are typically stored in secure facilities rather than being recycled.","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2012>48","subject":"Chemistry","year":"2012","type":"Objective","topic":"METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.","question":"A metal that is widely used in the manufacture of paints and overhead electric cables is","images":[],"options":{"A":"aluminium","B":"Copper","C":"Iron","D":"Lead"},"answer":"A","explanation":"Aluminium can be used to make paints (due to non-corrosive ability) and for electrical cables (due to its electrical conductivity).","marks":"1","difficulty":"1"},{"id":"objective>Chemistry>2012>49","subject":"Chemistry","year":"2012","type":"Objective","topic":"METALS AND THEIR COMPOUNDS : ALLOYS","question":"Brass is a mixture of","images":[],"options":{"A":"CU and Sn","B":"Cu and Zn","C":"CU and Mg","D":"Cu and Pb"},"answer":"B","explanation":"Brass is an alloy made primarily of copper (Cu) and zinc (Zn). The proportions of the copper and zinc can be varied to create a range of brasses with varying properties. It is used for its bright gold-like appearance and its relative resistance to tarnishing.","marks":"1","difficulty":"2"},{"id":"objective>Chemistry>2012>50","subject":"Chemistry","year":"2012","type":"Objective","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"Which of the following substances is mainly responsible for the depletion of the ozone layer?","images":[],"options":{"A":"Oxygen","B":"Chlorofluorocarbon","C":"Carbon(II)oxide","D":"Nitrogen(II)oxide"},"answer":"B","explanation":"Chlorofluorocarbons (CFCs) are the main cause of ozone layer depletion. When CFCs are released into the atmosphere, they can reach the stratosphere where they are broken down by solar radiation, releasing chlorine atoms. These chlorine atoms can catalyze the breakdown of ozone into oxygen, depleting the ozone layer.","marks":"1","difficulty":"1"}];